// ---- Scoring engine (group stage subset, mirrors ADMIN!D8:D10) ----
const PTS = { signo: 2, dif: 1, exacto: 3 };

function scoreMatch(pred, real) {
  if (!real) return { pts: 0, hit: null };
  const predSign = pred.local > pred.visitante ? "1" : pred.local < pred.visitante ? "2" : "X";
  const realSign = real.local > real.visitante ? "1" : real.local < real.visitante ? "2" : "X";
  let pts = 0;
  const detail = [];
  if (predSign === realSign) {
    pts += PTS.signo; detail.push("signo");
    const predDif = pred.local - pred.visitante;
    const realDif = real.local - real.visitante;
    if (predDif === realDif) { pts += PTS.dif; detail.push("dif"); }
    if (pred.local === real.local && pred.visitante === real.visitante) {
      pts += PTS.exacto; detail.push("exacto");
    }
  }
  const exact = pred.local === real.local && pred.visitante === real.visitante;
  return { pts, hit: exact ? "exacto" : predSign === realSign ? "signo" : "fallo", detail };
}

function totalFor(player, real) {
  let total = 0, played = 0, exactos = 0, signos = 0;
  for (const m of player.fase_grupos) {
    const r = real[m.partido];
    if (!r) continue;
    played++;
    const s = scoreMatch(m.pred, r);
    total += s.pts;
    if (s.hit === "exacto") exactos++;
    else if (s.hit === "signo") signos++;
  }
  return { total, played, exactos, signos };
}

// ---- Shared atoms ----
const C = {
  ink: "#0E1A2B", paper: "#FBF7EE", line: "#D8CFC0",
  pitch: "#1B5E3A", pitchLit: "#2E8B57", gold: "#C8A23A",
  rojo: "#C0392B", muted: "#6B7280", chalk: "#F4EFE3",
};

function Pill({ children, tone }) {
  const map = {
    exacto: { bg: "#1B5E3A", fg: "#F4EFE3" },
    signo: { bg: "#C8A23A", fg: "#0E1A2B" },
    fallo: { bg: "#E7DFD0", fg: "#9A8F7C" },
    pend: { bg: "transparent", fg: "#9A8F7C" },
  };
  const t = map[tone] || map.pend;
  return (
    <span style={{ background: t.bg, color: t.fg, fontSize: 10, fontWeight: 700,
      letterSpacing: ".06em", padding: "2px 7px", borderRadius: 2, textTransform: "uppercase",
      border: tone === "pend" ? "1px dashed " + C.line : "none" }}>{children}</span>
  );
}

function Score({ a, b }) {
  return <span style={{ fontFamily: "'DM Mono', monospace", fontWeight: 500 }}>{a}<span style={{ color: C.muted, margin: "0 3px" }}>–</span>{b}</span>;
}

// ---- Views ----
function Standings({ players, real, onPick }) {
  const rows = Object.values(players)
    .map((p) => ({ p, ...totalFor(p, real) }))
    .sort((a, b) => b.total - a.total || b.exactos - a.exactos);
  const max = Math.max(...rows.map((r) => r.total), 1);
  return (
    <div>
      <h2 style={hStyle}>Clasificación general</h2>
      <p style={subStyle}>Fase de grupos · {rows[0].played} de 72 partidos jugados</p>
      <div style={{ marginTop: 18 }}>
        {rows.map((r, i) => (
          <button key={r.p.id} onClick={() => onPick(r.p.id)}
            style={{ width: "100%", textAlign: "left", border: "none", background: "none",
              cursor: "pointer", padding: 0, display: "block" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "13px 4px",
              borderBottom: "1px solid " + C.line }}>
              <span style={{ fontFamily: "'Anton', sans-serif", fontSize: 26, width: 34,
                color: i === 0 ? C.gold : i < 3 ? C.ink : C.muted, lineHeight: 1 }}>
                {String(i + 1).padStart(2, "0")}</span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 700, fontSize: 16, color: C.ink }}>{r.p.nombre}</div>
                <div style={{ height: 6, background: C.chalk, borderRadius: 3, marginTop: 6, overflow: "hidden" }}>
                  <div style={{ width: (r.total / max * 100) + "%", height: "100%",
                    background: i === 0 ? C.gold : C.pitch, borderRadius: 3,
                    transition: "width .6s ease" }} />
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ fontFamily: "'Anton', sans-serif", fontSize: 24, color: C.ink, lineHeight: 1 }}>{r.total}</div>
                <div style={{ fontSize: 10, color: C.muted, letterSpacing: ".04em" }}>{r.exactos}✓ exactos</div>
              </div>
            </div>
          </button>
        ))}
      </div>
    </div>
  );
}

function PlayerView({ player, real }) {
  const t = totalFor(player, real);
  const h = player.cuadro_honor;
  return (
    <div>
      <h2 style={hStyle}>{player.nombre}</h2>
      <p style={subStyle}>{t.total} puntos · {t.exactos} resultados exactos · {t.signos} signos</p>
      <div style={{ display: "flex", gap: 8, marginTop: 16, flexWrap: "wrap" }}>
        <Honor label="Campeón" val={h.campeon} big />
        <Honor label="Subcampeón" val={h.subcampeon} />
        <Honor label="3º" val={h.tercero} />
        <Honor label="Bota de oro" val={h.bota_oro} />
        <Honor label="Balón de oro" val={h.balon_oro} />
      </div>
      <h3 style={{ ...hStyle, fontSize: 15, marginTop: 26 }}>Quiniela · fase de grupos</h3>
      <div style={{ marginTop: 10 }}>
        {player.fase_grupos.slice(0, 24).map((m, i) => {
          const r = real[m.partido];
          const s = scoreMatch(m.pred, r);
          return (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 10,
              padding: "9px 4px", borderBottom: "1px solid " + C.line, fontSize: 13.5 }}>
              <span style={{ flex: 1, color: C.ink }}>{m.local} <span style={{ color: C.muted }}>v</span> {m.visitante}</span>
              <span style={{ width: 52, textAlign: "center", color: C.muted }}>
                <Score a={m.pred.local} b={m.pred.visitante} /></span>
              <span style={{ width: 52, textAlign: "center" }}>
                {r ? <Score a={r.local} b={r.visitante} /> : <span style={{ color: C.line }}>· – ·</span>}</span>
              <span style={{ width: 64, textAlign: "right" }}>
                {r ? <Pill tone={s.hit}>{s.pts > 0 ? "+" + s.pts : "0"}</Pill> : <Pill tone="pend">—</Pill>}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function Honor({ label, val, big }) {
  return (
    <div style={{ flex: big ? "1 1 140px" : "1 1 90px", border: "1px solid " + C.line,
      borderRadius: 3, padding: "8px 10px", background: big ? C.ink : "transparent" }}>
      <div style={{ fontSize: 9, letterSpacing: ".08em", textTransform: "uppercase",
        color: big ? C.gold : C.muted, fontWeight: 700 }}>{label}</div>
      <div style={{ fontSize: big ? 16 : 13, fontWeight: 700, marginTop: 2,
        color: big ? C.chalk : C.ink }}>{val || "—"}</div>
    </div>
  );
}

function ByDay({ players, real }) {
  const fixtures = players.aldo.fase_grupos;
  const jornadas = ["J1", "J2", "J3"];
  const [j, setJ] = useState("J1");
  const list = fixtures.filter((m) => m.jornada === j);
  const ids = Object.keys(players);
  return (
    <div>
      <h2 style={hStyle}>Por jornada</h2>
      <div style={{ display: "flex", gap: 6, marginTop: 14 }}>
        {jornadas.map((x) => (
          <button key={x} onClick={() => setJ(x)} style={{ flex: 1, padding: "9px 0",
            border: "1px solid " + (j === x ? C.ink : C.line), background: j === x ? C.ink : "transparent",
            color: j === x ? C.chalk : C.ink, borderRadius: 3, fontWeight: 700, fontSize: 13,
            cursor: "pointer", letterSpacing: ".04em" }}>Jornada {x.slice(1)}</button>
        ))}
      </div>
      <div style={{ marginTop: 16 }}>
        {list.map((m, i) => {
          const r = real[m.partido];
          return (
            <div key={i} style={{ borderBottom: "1px solid " + C.line, padding: "12px 2px" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
                <span style={{ fontWeight: 700, fontSize: 14, color: C.ink }}>{m.local} – {m.visitante}</span>
                <span style={{ fontSize: 13 }}>{r ? <Score a={r.local} b={r.visitante} /> : <span style={{ color: C.muted, fontSize: 11 }}>sin jugar</span>}</span>
              </div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 8 }}>
                {ids.map((pid) => {
                  const pm = players[pid].fase_grupos.find((x) => x.partido === m.partido);
                  if (!pm) return null;
                  const s = scoreMatch(pm.pred, r);
                  return (
                    <span key={pid} style={{ fontSize: 11, border: "1px solid " + C.line,
                      borderRadius: 2, padding: "3px 6px", background: r ? (s.hit === "exacto" ? "#E6F0E9" : s.hit === "signo" ? "#F6EFD6" : C.paper) : C.paper }}>
                      <b style={{ color: C.ink }}>{players[pid].nombre.split(" ")[0]}</b>
                      <span style={{ color: C.muted, marginLeft: 5 }}>{pm.pred.local}-{pm.pred.visitante}</span>
                    </span>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function Admin({ players, real, setReal }) {
  const fixtures = players.aldo.fase_grupos.slice(0, 24);
  function upd(part, side, v) {
    const n = { ...real };
    const cur = n[part] || { local: "", visitante: "" };
    n[part] = { ...cur, [side]: v === "" ? "" : Math.max(0, parseInt(v) || 0) };
    if (n[part].local === "" && n[part].visitante === "") delete n[part];
    setReal(n);
  }
  return (
    <div>
      <h2 style={hStyle}>Resultados reales</h2>
      <p style={subStyle}>Introduce el marcador final. La clasificación se recalcula al instante.</p>
      <div style={{ marginTop: 14 }}>
        {fixtures.map((m, i) => {
          const r = real[m.partido] || {};
          return (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 8,
              padding: "8px 2px", borderBottom: "1px solid " + C.line, fontSize: 13 }}>
              <span style={{ flex: 1, color: C.ink }}>{m.local} – {m.visitante}</span>
              <input inputMode="numeric" value={r.local ?? ""} onChange={(e) => upd(m.partido, "local", e.target.value)}
                style={inp} />
              <span style={{ color: C.muted }}>:</span>
              <input inputMode="numeric" value={r.visitante ?? ""} onChange={(e) => upd(m.partido, "visitante", e.target.value)}
                style={inp} />
            </div>
          );
        })}
      </div>
    </div>
  );
}

const inp = { width: 38, textAlign: "center", padding: "6px 0", border: "1px solid " + C.line,
  borderRadius: 3, fontFamily: "'DM Mono', monospace", fontSize: 14, background: C.chalk };
const hStyle = { fontFamily: "'Anton', sans-serif", fontWeight: 400, fontSize: 22,
  color: C.ink, margin: 0, letterSpacing: ".01em", textTransform: "uppercase" };
const subStyle = { color: C.muted, fontSize: 12.5, margin: "5px 0 0", letterSpacing: ".02em" };

export default function App() {
  const [tab, setTab] = useState("clas");
  const [real, setReal] = useState(INITIAL_REAL);
  const [picked, setPicked] = useState("aldo");
  const players = DATA.players;

  const tabs = [
    ["clas", "Clasificación"],
    ["dia", "Por jornada"],
    ["jug", "Jugador"],
    ["admin", "Admin"],
  ];

  return (
    <div style={{ minHeight: "100%", background: C.paper, color: C.ink,
      fontFamily: "'Inter', system-ui, sans-serif" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Anton&family=Inter:wght@400;500;700&family=DM+Mono:wght@400;500&display=swap');
        * { box-sizing: border-box; } button:focus-visible { outline: 2px solid ${C.pitch}; outline-offset: 2px; }
        input:focus { outline: 2px solid ${C.pitch}; outline-offset: 1px; }`}</style>

      <div style={{ maxWidth: 460, margin: "0 auto", padding: "0 0 90px" }}>
        {/* Header */}
        <header style={{ padding: "22px 20px 16px", borderBottom: "2px solid " + C.ink,
          background: "linear-gradient(180deg," + C.pitch + " 0%," + C.pitchLit + " 100%)" }}>
          <div style={{ fontSize: 10, letterSpacing: ".22em", color: C.chalk, opacity: .85,
            textTransform: "uppercase", fontWeight: 700 }}>La Porra · Norteamérica</div>
          <div style={{ fontFamily: "'Anton', sans-serif", fontSize: 40, color: C.chalk,
            lineHeight: .95, marginTop: 4, letterSpacing: ".01em" }}>MUNDIAL<br />2026</div>
        </header>

        {/* Content */}
        <main style={{ padding: "20px" }}>
          {tab === "clas" && <Standings players={players} real={real} onPick={(id) => { setPicked(id); setTab("jug"); }} />}
          {tab === "dia" && <ByDay players={players} real={real} />}
          {tab === "jug" && (
            <div>
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 18 }}>
                {Object.values(players).map((p) => (
                  <button key={p.id} onClick={() => setPicked(p.id)} style={{ fontSize: 12,
                    padding: "6px 10px", borderRadius: 20, cursor: "pointer", fontWeight: 700,
                    border: "1px solid " + (picked === p.id ? C.ink : C.line),
                    background: picked === p.id ? C.ink : "transparent",
                    color: picked === p.id ? C.chalk : C.ink }}>{p.nombre}</button>
                ))}
              </div>
              <PlayerView player={players[picked]} real={real} />
            </div>
          )}
          {tab === "admin" && <Admin players={players} real={real} setReal={setReal} />}
        </main>

        {/* Bottom nav */}
        <nav style={{ position: "fixed", bottom: 0, left: 0, right: 0, maxWidth: 460,
          margin: "0 auto", display: "flex", borderTop: "1px solid " + C.line,
          background: C.paper }}>
          {tabs.map(([id, label]) => (
            <button key={id} onClick={() => setTab(id)} style={{ flex: 1, padding: "12px 4px 14px",
              border: "none", background: "none", cursor: "pointer",
              borderTop: "3px solid " + (tab === id ? C.pitch : "transparent"),
              color: tab === id ? C.ink : C.muted, fontWeight: tab === id ? 700 : 500,
              fontSize: 11.5, letterSpacing: ".02em" }}>{label}</button>
          ))}
        </nav>
      </div>
    </div>
  );
}
